CREATE VIEW visitas.v_puntosdeventa AS
 SELECT pdv.id AS pdv_id,
    pdv.nombre AS punto_venta,
    pdv.mac_address,
    pdv.direccion,
    pdv.activo,
    o.nombre AS oficina,
    c.nombre AS celula,
    s.nombre AS subzona,
    z.nombre AS zona,
    d.nombre AS departamento
   FROM (((((visitas.puntosdeventa pdv
     JOIN visitas.oficinas o ON ((o.id = pdv.oficina_id)))
     JOIN visitas.celulas c ON ((c.id = o.celula_id)))
     JOIN visitas.subzonas s ON ((s.id = c.subzona_id)))
     JOIN visitas.zonas z ON ((z.id = s.zona_id)))
     JOIN visitas.departamentos d ON ((d.id = z.departamento_id)))
  ORDER BY d.nombre, z.nombre, s.nombre, c.nombre, o.nombre, pdv.nombre;


