--
-- TOC entry 5230 (class 2618 OID 24769)
-- Name: v_personas_huellas _RETURN; Type: RULE; Schema: visitas; Owner: postgres
--

CREATE OR REPLACE VIEW visitas.v_personas_huellas AS
 SELECT p.id,
    p.documento,
    p.tipo_documento,
    (((p.nombres)::text || ' '::text) || (p.apellidos)::text) AS nombre_completo,
    p.departamento AS empresa,
    p.activo,
    count(h.id) AS total_huellas,
    max(h.created_at) AS ultima_huella,
    p.created_at
   FROM (visitas.personas p
     LEFT JOIN visitas.huellas h ON (((h.persona_id = p.id) AND (h.activo = true))))
  GROUP BY p.id
  ORDER BY p.apellidos, p.nombres;


